/**
 * Auth Controller Tests
 *
 * Unit tests for AuthController covering:
 * - Request/response handling
 * - HTTP status codes
 * - Cookie management
 * - Input validation delegation
 * - Service method invocation
 *
 * @module modules/_core/auth/__tests__/auth.controller.spec
 */

import { describe, it, expect, beforeEach, vi, type Mock } from 'vitest';
import type { Request, Response } from 'express';

import { AuthController } from '@/modules/_core/auth/auth.controller';
import type { AuthModuleService } from '@/modules/_core/auth/auth.service';
import type { AuthUser, AuthenticatedRequest } from '@/core/middleware/auth.middleware';

// Mock the env module
vi.mock('@/config/env', () => ({
  env: {
    NODE_ENV: 'test',
  },
}));

// -----------------------------------------------------------------------------
// Mock Factories
// -----------------------------------------------------------------------------

/**
 * Creates a mock AuthModuleService
 */
function createMockAuthService(): {
  register: Mock;
  login: Mock;
  refreshTokens: Mock;
  logout: Mock;
  forgotPassword: Mock;
  resetPassword: Mock;
  verifyEmail: Mock;
  resendVerification: Mock;
  changePassword: Mock;
  getSessions: Mock;
  revokeSession: Mock;
} {
  return {
    register: vi.fn(),
    login: vi.fn(),
    refreshTokens: vi.fn(),
    logout: vi.fn(),
    forgotPassword: vi.fn(),
    resetPassword: vi.fn(),
    verifyEmail: vi.fn(),
    resendVerification: vi.fn(),
    changePassword: vi.fn(),
    getSessions: vi.fn(),
    revokeSession: vi.fn(),
  };
}

/**
 * Creates a mock Express Request
 */
function createMockRequest(overrides: Partial<Request> = {}): Request {
  return {
    body: {},
    params: {},
    query: {},
    headers: {},
    cookies: {},
    ip: '127.0.0.1',
    socket: { remoteAddress: '127.0.0.1' },
    ...overrides,
  } as unknown as Request;
}

/**
 * Creates a mock authenticated request
 */
function createMockAuthenticatedRequest(
  user: AuthUser,
  tokenPayload?: { jti: string },
  overrides: Partial<Request> = {}
): AuthenticatedRequest {
  const req = createMockRequest(overrides) as AuthenticatedRequest;
  req.user = user;
  req.tokenPayload = tokenPayload;
  return req;
}

/**
 * Creates a mock Express Response
 */
function createMockResponse(): Response & {
  statusCode: number;
  jsonData: unknown;
  cookieData: { name: string; value: string; options: Record<string, unknown> }[];
  clearedCookies: { name: string; options: Record<string, unknown> }[];
} {
  const res: Partial<Response> & {
    statusCode: number;
    jsonData: unknown;
    cookieData: { name: string; value: string; options: Record<string, unknown> }[];
    clearedCookies: { name: string; options: Record<string, unknown> }[];
  } = {
    statusCode: 200,
    jsonData: null,
    cookieData: [],
    clearedCookies: [],
  };

  res.status = vi.fn((code: number) => {
    res.statusCode = code;
    return res as Response;
  });

  res.json = vi.fn((data: unknown) => {
    res.jsonData = data;
    return res as Response;
  });

  res.send = vi.fn(() => res as Response);

  res.cookie = vi.fn((name: string, value: string, options: Record<string, unknown>) => {
    res.cookieData.push({ name, value, options });
    return res as Response;
  });

  res.clearCookie = vi.fn((name: string, options: Record<string, unknown>) => {
    res.clearedCookies.push({ name, options });
    return res as Response;
  });

  res.setHeader = vi.fn(() => res as Response);

  return res as Response & {
    statusCode: number;
    jsonData: unknown;
    cookieData: { name: string; value: string; options: Record<string, unknown> }[];
    clearedCookies: { name: string; options: Record<string, unknown> }[];
  };
}

/**
 * Creates a mock AuthUser for testing
 */
function createMockAuthUser(overrides: Partial<AuthUser> = {}): AuthUser {
  return {
    id: 'user_123',
    organizationId: 'org_123',
    role: 'owner',
    permissions: ['menu.view', 'menu.create'],
    ...overrides,
  };
}

// -----------------------------------------------------------------------------
// Test Suite
// -----------------------------------------------------------------------------

describe('AuthController', () => {
  let controller: AuthController;
  let mockAuthService: ReturnType<typeof createMockAuthService>;

  beforeEach(() => {
    mockAuthService = createMockAuthService();
    controller = new AuthController(mockAuthService as unknown as AuthModuleService);
  });

  // ---------------------------------------------------------------------------
  // Registration Tests
  // ---------------------------------------------------------------------------

  describe('register', () => {
    const validRegisterData = {
      email: 'newuser@example.com',
      password: 'SecurePassword123!',
      passwordConfirm: 'SecurePassword123!',
      firstName: 'Jane',
      lastName: 'Smith',
      acceptTerms: true,
    };

    it('should return success response with 201 status', async () => {
      // Arrange
      const serviceResponse = {
        userId: 'user_new',
        email: validRegisterData.email,
        requiresEmailVerification: true,
        message: 'Registration successful',
      };
      mockAuthService.register.mockResolvedValue(serviceResponse);

      // Act
      const result = await controller.register(validRegisterData);

      // Assert
      expect(result).toEqual({
        success: true,
        data: serviceResponse,
      });
      expect(mockAuthService.register).toHaveBeenCalledWith(validRegisterData);
    });
  });

  // ---------------------------------------------------------------------------
  // Login Tests
  // ---------------------------------------------------------------------------

  describe('login', () => {
    const validLoginData = {
      email: 'test@example.com',
      password: 'Password123!',
    };

    it('should return tokens and set refresh token cookie', async () => {
      // Arrange
      const serviceResponse = {
        user: {
          id: 'user_123',
          email: 'test@example.com',
          firstName: 'John',
          lastName: 'Doe',
          organizationId: 'org_123',
          organizationName: 'Test Org',
          role: 'owner',
          permissions: ['menu.view'],
          emailVerified: true,
        },
        tokens: {
          accessToken: 'access_token_123',
          refreshToken: 'refresh_token_456',
          expiresIn: 900000,
          tokenType: 'Bearer' as const,
        },
      };
      mockAuthService.login.mockResolvedValue(serviceResponse);

      const req = createMockRequest({
        headers: { 'user-agent': 'Test Browser' },
      });
      const res = createMockResponse();

      // Act
      await controller.login(validLoginData, req, res);

      // Assert
      expect(mockAuthService.login).toHaveBeenCalledWith(validLoginData, {
        ipAddress: '127.0.0.1',
        userAgent: 'Test Browser',
      });

      // Check cookie was set
      expect(res.cookie).toHaveBeenCalledWith(
        'refreshToken',
        'refresh_token_456',
        expect.objectContaining({
          httpOnly: true,
          sameSite: 'strict',
          path: '/api/v1/auth',
        })
      );

      // Check response format (refresh token should NOT be in body)
      expect(res.json).toHaveBeenCalled();
      expect(res.jsonData).toEqual({
        success: true,
        data: {
          user: serviceResponse.user,
          tokens: {
            accessToken: 'access_token_123',
            expiresIn: 900000,
            tokenType: 'Bearer',
          },
        },
      });
    });
  });

  // ---------------------------------------------------------------------------
  // Token Refresh Tests
  // ---------------------------------------------------------------------------

  describe('refresh', () => {
    it('should refresh tokens and set new cookie', async () => {
      // Arrange
      const serviceResponse = {
        tokens: {
          accessToken: 'new_access_token',
          refreshToken: 'new_refresh_token',
          expiresIn: 900000,
          tokenType: 'Bearer' as const,
        },
      };
      mockAuthService.refreshTokens.mockResolvedValue(serviceResponse);

      const res = createMockResponse();

      // Act
      await controller.refresh('old_refresh_token', res);

      // Assert
      expect(mockAuthService.refreshTokens).toHaveBeenCalledWith('old_refresh_token');

      // Check new cookie was set
      expect(res.cookie).toHaveBeenCalledWith(
        'refreshToken',
        'new_refresh_token',
        expect.objectContaining({
          httpOnly: true,
        })
      );

      expect(res.json).toHaveBeenCalled();
    });
  });

  // ---------------------------------------------------------------------------
  // Logout Tests
  // ---------------------------------------------------------------------------

  describe('logout', () => {
    it('should logout and clear refresh token cookie', async () => {
      // Arrange
      mockAuthService.logout.mockResolvedValue({ message: 'Logged out successfully' });

      const user = createMockAuthUser();
      const req = createMockAuthenticatedRequest(user, { jti: 'token_id_123' });
      const res = createMockResponse();

      // Act
      await controller.logout({ allDevices: false }, user, req, res);

      // Assert
      expect(mockAuthService.logout).toHaveBeenCalledWith('user_123', 'token_id_123', {
        allDevices: false,
      });

      // Check cookie was cleared
      expect(res.clearCookie).toHaveBeenCalledWith(
        'refreshToken',
        expect.objectContaining({
          httpOnly: true,
          path: '/api/v1/auth',
        })
      );

      expect(res.statusCode).toBe(204);
    });
  });

  // ---------------------------------------------------------------------------
  // Password Reset Tests
  // ---------------------------------------------------------------------------

  describe('forgotPassword', () => {
    it('should return success message', async () => {
      // Arrange
      const serviceResponse = {
        message: 'If an account exists, a reset link has been sent',
      };
      mockAuthService.forgotPassword.mockResolvedValue(serviceResponse);

      // Act
      const result = await controller.forgotPassword({ email: 'test@example.com' });

      // Assert
      expect(result).toEqual({
        success: true,
        data: serviceResponse,
      });
      expect(mockAuthService.forgotPassword).toHaveBeenCalledWith({ email: 'test@example.com' });
    });
  });

  describe('resetPassword', () => {
    it('should reset password and return success', async () => {
      // Arrange
      const resetData = {
        token: 'reset_token_123',
        password: 'NewPassword123!',
        passwordConfirm: 'NewPassword123!',
      };
      const serviceResponse = { message: 'Password reset successfully' };
      mockAuthService.resetPassword.mockResolvedValue(serviceResponse);

      // Act
      const result = await controller.resetPassword(resetData);

      // Assert
      expect(result).toEqual({
        success: true,
        data: serviceResponse,
      });
      expect(mockAuthService.resetPassword).toHaveBeenCalledWith(resetData);
    });
  });

  describe('changePassword', () => {
    it('should change password for authenticated user', async () => {
      // Arrange
      const changeData = {
        currentPassword: 'OldPassword123!',
        newPassword: 'NewPassword456!',
        newPasswordConfirm: 'NewPassword456!',
      };
      const serviceResponse = { message: 'Password changed', sessionsRevoked: true };
      mockAuthService.changePassword.mockResolvedValue(serviceResponse);

      const user = createMockAuthUser();

      // Act
      const result = await controller.changePassword(changeData, user);

      // Assert
      expect(result).toEqual({
        success: true,
        data: serviceResponse,
      });
      expect(mockAuthService.changePassword).toHaveBeenCalledWith('user_123', changeData);
    });
  });

  // ---------------------------------------------------------------------------
  // Email Verification Tests
  // ---------------------------------------------------------------------------

  describe('verifyEmail', () => {
    it('should verify email and return success', async () => {
      // Arrange
      const serviceResponse = { message: 'Email verified', verified: true };
      mockAuthService.verifyEmail.mockResolvedValue(serviceResponse);

      // Act
      const result = await controller.verifyEmail({ token: 'verify_token_123' });

      // Assert
      expect(result).toEqual({
        success: true,
        data: serviceResponse,
      });
      expect(mockAuthService.verifyEmail).toHaveBeenCalledWith({ token: 'verify_token_123' });
    });
  });

  describe('resendVerification', () => {
    it('should resend verification email', async () => {
      // Arrange
      const serviceResponse = { message: 'Verification email sent' };
      mockAuthService.resendVerification.mockResolvedValue(serviceResponse);

      // Act
      const result = await controller.resendVerification({ email: 'test@example.com' });

      // Assert
      expect(result).toEqual({
        success: true,
        data: serviceResponse,
      });
      expect(mockAuthService.resendVerification).toHaveBeenCalledWith({ email: 'test@example.com' });
    });
  });

  // ---------------------------------------------------------------------------
  // Current User Tests
  // ---------------------------------------------------------------------------

  describe('me', () => {
    it('should return current user information', async () => {
      // Arrange
      const user = createMockAuthUser();

      // Act
      const result = await controller.me(user);

      // Assert
      expect(result).toEqual({
        success: true,
        data: user,
      });
    });
  });

  // ---------------------------------------------------------------------------
  // Session Management Tests
  // ---------------------------------------------------------------------------

  describe('getSessions', () => {
    it('should return user sessions', async () => {
      // Arrange
      const sessions = [
        {
          id: 'session_1',
          userId: 'user_123',
          organizationId: 'org_123',
          role: 'owner',
          tokenId: 'token_1',
          ipAddress: '192.168.1.1',
          userAgent: 'Chrome',
          createdAt: new Date().toISOString(),
          lastActivityAt: new Date().toISOString(),
          isCurrent: true,
        },
      ];
      mockAuthService.getSessions.mockResolvedValue(sessions);

      const user = createMockAuthUser();
      const req = createMockAuthenticatedRequest(user, { jti: 'token_1' });

      // Act
      const result = await controller.getSessions(user, req);

      // Assert
      expect(result).toEqual({
        success: true,
        data: sessions,
      });
      expect(mockAuthService.getSessions).toHaveBeenCalledWith('user_123', 'token_1');
    });
  });

  describe('revokeSession', () => {
    it('should revoke a specific session', async () => {
      // Arrange
      mockAuthService.revokeSession.mockResolvedValue(undefined);

      const user = createMockAuthUser();

      // Act
      await controller.revokeSession('session_to_revoke', user);

      // Assert
      expect(mockAuthService.revokeSession).toHaveBeenCalledWith('user_123', 'session_to_revoke');
    });
  });
});
